local Players=game:GetService("Players")local ReplicatedStorage=game:GetService("ReplicatedStorage")local LocalPlayer=Players.LocalPlayer local Remotes=ReplicatedStorage:WaitForChild("Remotes")local OpenCaseRemote=Remotes:WaitForChild("OpenCase")local SellRemote=Remotes:WaitForChild("Sell")local RedeemCodeRemote=Remotes:WaitForChild("RedeemCode")local Modules=ReplicatedStorage:WaitForChild("Modules")local Cases=require(Modules:WaitForChild("Cases"))local Rayfield=loadstring(game:HttpGet("https://sirius.menu/rayfield"))()local function errNotify(msg)pcall(function()Rayfield:Notify({Title="Error",Content=tostring(msg),Duration=4,Image=0})end)end local function childValue(obj,name,fallback)local c=obj:FindFirstChild(name)if c and c:IsA("ValueBase")then return c.Value end return fallback end local function loadCasesFromModule()local casesModule=Modules:FindFirstChild("Cases")if not casesModule or not casesModule:IsA("ModuleScript")then return nil end local ok,casesTable=pcall(require,casesModule)if not ok or type(casesTable)~="table"then return nil end local dropdownOptions={}local shownToId={}for internalId,data in pairs(casesTable)do local display=(type(data)=="table"and(data.Name or data.DisplayName or data.title))or tostring(internalId)local shown=string.format("%s  [%s]",tostring(display),tostring(internalId))table.insert(dropdownOptions,shown)shownToId[shown]=tostring(internalId)end table.sort(dropdownOptions)return dropdownOptions,shownToId end local function loadCasesFallbackFromWildPrices()local misc=ReplicatedStorage:FindFirstChild("Misc")if not misc then return nil end local wildPrices=misc:FindFirstChild("WildPrices")if not wildPrices then return nil end local dropdownOptions={}local shownToId={}for _,child in ipairs(wildPrices:GetChildren())do local internalId=child.Name local shown=string.format("%s  [%s]",internalId,internalId)table.insert(dropdownOptions,shown)shownToId[shown]=internalId end table.sort(dropdownOptions)return dropdownOptions,shownToId end local caseOptions,caseShownToId=loadCasesFromModule()if not caseOptions or#caseOptions==0 then caseOptions,caseShownToId=loadCasesFallbackFromWildPrices()end if not caseOptions or#caseOptions==0 then caseOptions,caseShownToId={"No cases found"},{}end local function loadAllSkinsFromItemsModule()local itemsModule=Modules:FindFirstChild("Items")if not itemsModule or not itemsModule:IsA("ModuleScript")then return{"No skins found"}end local ok,itemsTable=pcall(require,itemsModule)if not ok or type(itemsTable)~="table"then return{"No skins found"}end local dict=(type(itemsTable.Skins)=="table")and itemsTable.Skins or itemsTable local set={}for k,v in pairs(dict)do if type(k)=="string"then set[k]=true elseif type(v)=="table"and type(v.Name)=="string"then set[v.Name]=true end end local list={}for name in pairs(set)do table.insert(list,name)end table.sort(list)if#list==0 then return{"No skins found"}end return list end local skinOptions=loadAllSkinsFromItemsModule()local function getValueOrAttribute(inst,key)local attr=inst:GetAttribute(key)if attr~=nil then return attr end local child=inst:FindFirstChild(key)if child and child:IsA("ValueBase")then return child.Value end local child2=inst:FindFirstChild(string.lower(key))if child2 and child2:IsA("ValueBase")then return child2.Value end local attr2=inst:GetAttribute(string.lower(key))if attr2~=nil then return attr2 end return nil end local function readInventoryEntries()local playerData=LocalPlayer:FindFirstChild("PlayerData")if not playerData then return nil,"PlayerData not found."end local inv=playerData:FindFirstChild("Inventory")if not inv then return nil,"Inventory not found at PlayerData.Inventory."end if inv:IsA("ValueBase")then return nil,"Inventory is a ValueObject; script expects Inventory children."end local out={}for _,itemInst in ipairs(inv:GetChildren())do local wear=getValueOrAttribute(itemInst,"Wear")or"Field-Tested"local stattrak=getValueOrAttribute(itemInst,"Stattrak")local name=getValueOrAttribute(itemInst,"Name")local age=getValueOrAttribute(itemInst,"Age")if not name or name==""then name=itemInst.Name end if type(stattrak)~="boolean"then if stattrak==nil then stattrak=false elseif type(stattrak)=="string"then stattrak=(stattrak:lower()=="true")elseif type(stattrak)=="number"then stattrak=(stattrak~=0)else stattrak=false end end if type(age)~="number"then age=tonumber(age)or os.time()end table.insert(out,{Wear=tostring(wear),Stattrak=stattrak,Name=tostring(name),Age=age,})end return out,nil end local function buildQuestTitle(q)local qType=(q:IsA("ValueBase")and q.Value)or"Unknown"local req=childValue(q,"Requirement",0)local subject=childValue(q,"Subject","")if qType=="Open"then local caseName=(subject~=""and Cases[subject]and Cases[subject].Name)or subject return("Open %s %s(s)."):format(tostring(req),tostring(caseName))elseif qType=="Play"then return("Play %s %s mode battles."):format(tostring(req),tostring(subject))elseif qType=="Win"then return("Win %s battles."):format(tostring(req))end return("Quest type: %s"):format(tostring(qType))end local function buildQuestParagraphContent()local questsFolder=LocalPlayer:FindFirstChild("PlayerData")and LocalPlayer.PlayerData:FindFirstChild("Quests")if not questsFolder then return"Quests folder not found."end local lines={}for i,q in ipairs(questsFolder:GetChildren())do local progress=childValue(q,"Progress",0)local req=childValue(q,"Requirement",0)local title=buildQuestTitle(q)table.insert(lines,string.format("[%d] %s  (%s/%s)",i,title,tostring(progress),tostring(req)))end if#lines==0 then return"No quests found."end return table.concat(lines,"\n")end local Window=Rayfield:CreateWindow({Name="Case Opener",Icon=0,LoadingTitle="Case Opener",LoadingSubtitle="Rayfield UI",Theme="Default",ToggleUIKeybind=Enum.KeyCode.RightControl,ConfigurationSaving={Enabled=true,FolderName="ScriptZRoblox CaseParadise",FileName="Settings"},Discord={Enabled=false,Invite="",RememberJoins=true},KeySystem=false})local MainTab=Window:CreateTab("Main",0)local MiscTab=Window:CreateTab("Other",0)local SettingsTab=Window:CreateTab("Settings",0)MainTab:CreateSection("Case Controls")local selectedCaseIds={}local openAmount=1 MainTab:CreateDropdown({Name="Cases",Options=caseOptions,CurrentOption={},MultipleOptions=true,Flag="CaseSelect",Callback=function(selected)local ids={}for _,display in ipairs(selected)do local id=caseShownToId[display]if id then table.insert(ids,id)end end selectedCaseIds=ids end})MainTab:CreateSlider({Name="Amount",Range={1,5},Increment=1,Suffix="x",CurrentValue=1,Flag="OpenAmount",Callback=function(val)openAmount=math.clamp(math.floor(tonumber(val)or 1),1,5)end})local autoOpenEnabled=false local openLoopNonce=0 MainTab:CreateToggle({Name="Auto-Open Cases",CurrentValue=false,Flag="AutoOpen",Callback=function(state)autoOpenEnabled=state openLoopNonce+=1 local myNonce=openLoopNonce if not autoOpenEnabled then return end task.spawn(function()local currentCaseIndex=1 while autoOpenEnabled and myNonce==openLoopNonce do local caseList=selectedCaseIds if#caseList==0 then errNotify("No case selected.")else local caseId=caseList[currentCaseIndex]local shouldSkip=false if caseId=="HazardousCase"then local currencies=LocalPlayer:FindFirstChild("PlayerData")and LocalPlayer.PlayerData:FindFirstChild("Currencies")local tickets=currencies and currencies:FindFirstChild("Tickets")if tickets and tickets:IsA("ValueBase")and tickets.Value<50 then shouldSkip=true end end if not shouldSkip then local ok,err=pcall(function()OpenCaseRemote:InvokeServer(caseId,openAmount,false,false)end)if not ok then errNotify("OpenCase failed.")warn(err)end end currentCaseIndex=currentCaseIndex%#caseList+1 end task.wait(8)end end)end})MainTab:CreateSection("Auto Sell")local protectedSet={}MainTab:CreateDropdown({Name="Dont sell",Options=skinOptions,CurrentOption={},MultipleOptions=true,Flag="ProtectedSkins",Callback=function(selected)protectedSet={}if type(selected)=="table"then for _,name in ipairs(selected)do protectedSet[tostring(name)]=true end end end})local autoSellEnabled=false local sellLoopNonce=0 MainTab:CreateToggle({Name="Auto Sell",CurrentValue=false,Flag="AutoSell",Callback=function(state)autoSellEnabled=state sellLoopNonce+=1 local myNonce=sellLoopNonce if not autoSellEnabled then return end task.spawn(function()while autoSellEnabled and myNonce==sellLoopNonce do local entries,invErr=readInventoryEntries()if not entries then errNotify(invErr or"Failed to read inventory.")task.wait(5)continue end local payload={}for _,e in ipairs(entries)do if not protectedSet[e.Name]then table.insert(payload,{Wear=e.Wear,Stattrak=e.Stattrak,Name=e.Name,Age=e.Age})end end if#payload>0 then local BATCH_SIZE=50 local i=1 while i<=#payload do if not(autoSellEnabled and myNonce==sellLoopNonce)then break end local batch={}for j=i,math.min(i+BATCH_SIZE-1,#payload)do table.insert(batch,payload[j])end local ok,err=pcall(function()SellRemote:InvokeServer(batch)end)if not ok then errNotify("Sell failed.")warn(err)break end i+=BATCH_SIZE task.wait(0.2)end end task.wait(5)end end)end})MainTab:CreateSection("Auto Quest")local QuestParagraph=MainTab:CreateParagraph({Title="Quests",Content=buildQuestParagraphContent()})local function refreshQuestParagraph()QuestParagraph:Set({Title="Quests",Content=buildQuestParagraphContent()})end local function getPlayerBattleId()local battles=ReplicatedStorage:FindFirstChild("Battles")if not battles then return nil end for _,battleIdObj in ipairs(battles:GetChildren())do if battleIdObj:IsA("NumberValue")then local battleId=battleIdObj.Name local playersFolder=battleIdObj:FindFirstChild("Players")if playersFolder and playersFolder:FindFirstChild(LocalPlayer.Name)then return battleId end end end return nil end local function getCaseIdFromName(caseName)local casesModule=Modules:FindFirstChild("Cases")if casesModule and casesModule:IsA("ModuleScript")then local ok,casesTable=pcall(require,casesModule)if ok and type(casesTable)=="table"then for internalId,data in pairs(casesTable)do local display=(type(data)=="table"and(data.Name or data.DisplayName or data.title))or tostring(internalId)if display:lower()==caseName:lower()or internalId:lower()==caseName:lower()then return tostring(internalId)end end end end return caseName end local function processQuest(quest)if not quest then return false end local qType=(quest:IsA("ValueBase")and quest.Value)or"Unknown"local requirement=childValue(quest,"Requirement",0)local subject=childValue(quest,"Subject","")local progress=childValue(quest,"Progress",0)if progress>=requirement then return true end if qType=="Win"then local battleId=getPlayerBattleId()if not battleId then local success,result=pcall(function()return ReplicatedStorage.Remotes.CreateBattle:InvokeServer({"PERCHANCE"},2,"CLASSIC",false)end)if success and result then task.wait(3)battleId=getPlayerBattleId()end end if battleId then pcall(function()ReplicatedStorage.Remotes.AddBot:FireServer(battleId,LocalPlayer)end)return true end elseif qType=="Open"then local caseId=getCaseIdFromName(subject)if caseId and caseId~=""then local ok,err=pcall(function()OpenCaseRemote:InvokeServer(caseId,5,false,false)task.wait(2)end)return ok end elseif qType=="Play"then local battleId=getPlayerBattleId()local battleMode="CLASSIC"if subject~=""then local subjectLower=subject:lower()if subjectLower:find("terminal")then battleMode="TERMINAL"elseif subjectLower:find("classic")then battleMode="CLASSIC"elseif subjectLower:find("jester")then battleMode="JESTER"elseif subjectLower:find("shared")then battleMode="SHARED"elseif subjectLower:find("jackpot")then battleMode="JACKPOT"elseif subjectLower:find("crazy terminal")then battleMode="CRAZY TERMINAL"else battleMode=subject:upper()end end if not battleId then local success,result=pcall(function()return ReplicatedStorage.Remotes.CreateBattle:InvokeServer({"PERCHANCE"},2,battleMode,false)end)if success and result then task.wait(3)battleId=getPlayerBattleId()end end if battleId then pcall(function()ReplicatedStorage.Remotes.AddBot:FireServer(battleId,LocalPlayer)task.wait(7)end)return true end end return false end local autoQuestEnabled=false local questLoopNonce=0 MainTab:CreateToggle({Name="Auto Quest",CurrentValue=false,Flag="AutoQuest",Callback=function(state)autoQuestEnabled=state questLoopNonce+=1 local myNonce=questLoopNonce if not autoQuestEnabled then return end task.spawn(function()while autoQuestEnabled and myNonce==questLoopNonce do local questsFolder=LocalPlayer:FindFirstChild("PlayerData")and LocalPlayer.PlayerData:FindFirstChild("Quests")if questsFolder then for _,quest in ipairs(questsFolder:GetChildren())do if not(autoQuestEnabled and myNonce==questLoopNonce)then break end local progress=childValue(quest,"Progress",0)local requirement=childValue(quest,"Requirement",0)if progress<requirement then local processed=processQuest(quest)refreshQuestParagraph()if processed then task.wait(3)else task.wait(3)end break end end end task.wait(5)end end)end})task.spawn(function()while true do refreshQuestParagraph()task.wait(1)end end)MiscTab:CreateSection("Codes")local CODES={"welcome","secret","update","release"}MiscTab:CreateButton({Name="Claim All Codes",Callback=function()for _,code in ipairs(CODES)do local ok,err=pcall(function()RedeemCodeRemote:FireServer(code)task.wait(1)end)if not ok then errNotify("RedeemCode failed for: "..tostring(code))warn(err)end task.wait(0.5)end end})MiscTab:CreateSection("Auto Claim Rewards (bugged)")local autoClaimEnabled=false local claimLoopNonce=0 local currentGiftIndex=1 local GIFT_NAMES={"Gift1","Gift2","Gift3","Gift4","Gift5","Gift6","Gift7","Gift8","Gift9"}local function isGiftClaimed(giftName)local claimedGifts=LocalPlayer:FindFirstChild("ClaimedGifts")if not claimedGifts then return false end local giftBool=claimedGifts:FindFirstChild(giftName)if giftBool and giftBool:IsA("BoolValue")then return giftBool.Value end return false end local function clickReturnButton()task.wait(0.5)local success=pcall(function()local playerGui=LocalPlayer:FindFirstChild("PlayerGui")if not playerGui then return end local openAnimation=playerGui:FindFirstChild("OpenAnimation")if not openAnimation then return end local endPreview=openAnimation:FindFirstChild("EndPreview")if not endPreview then return end local returnButton=endPreview:FindFirstChild("ReturnButton")if returnButton and returnButton:IsA("ImageButton")then returnButton.MouseButton1Click:Fire()Rayfield:Notify({Title="Auto Claim",Content="Clicked Return button",Duration=1,Image=0})end end)if not success then warn("Failed to click Return button")end end local function getNextUnclaimedGift(startIndex)local totalGifts=#GIFT_NAMES for i=1,totalGifts do local checkIndex=((startIndex+i-2)%totalGifts)+1 local giftName=GIFT_NAMES[checkIndex]if not isGiftClaimed(giftName)then return checkIndex,giftName end end return nil,nil end MiscTab:CreateToggle({Name="Auto Claim Rewards",CurrentValue=false,Flag="AutoClaimRewards",Callback=function(state)autoClaimEnabled=state claimLoopNonce+=1 local myNonce=claimLoopNonce if not autoClaimEnabled then currentGiftIndex=1 return end task.spawn(function()while autoClaimEnabled and myNonce==claimLoopNonce do local nextIndex,nextGift=getNextUnclaimedGift(currentGiftIndex)if nextGift then local success,result=pcall(function()return ReplicatedStorage.Remotes.OpenCase:InvokeServer(nextGift,-1,false)end)if success then currentGiftIndex=(nextIndex%9)+1 else warn("Failed to claim "..nextGift..": "..tostring(result))currentGiftIndex=(nextIndex%9)+1 end else autoClaimEnabled=false for _,toggle in pairs(MainTab.toggles or{})do if toggle.Flag=="AutoClaimRewards"then toggle:Set(false)break end end break end task.wait(7)clickReturnButton()task.wait(2)end end)end})SettingsTab:CreateSection("Configuration")SettingsTab:CreateParagraph({Title="Auto‑Save",Content="All settings are saved automatically when you change them and will be restored the next time you run the script."})SettingsTab:CreateButton({Name="Reset Saved Settings",Callback=function()local success=pcall(function()Rayfield:Configuration():Reset()Rayfield:Notify({Title="Settings Reset",Content="Configuration has been cleared. Reload the UI to see defaults.",Duration=3})end)if not success then errNotify("Failed to reset configuration.")end end})